// Bitmask — values may be combined with |.
type VER_FLAGS uint32

const (
	VER_MINORVERSION     VER_FLAGS = 1
	VER_MAJORVERSION     VER_FLAGS = 2
	VER_BUILDNUMBER      VER_FLAGS = 4
	VER_PLATFORMID       VER_FLAGS = 8
	VER_SERVICEPACKMINOR VER_FLAGS = 16
	VER_SERVICEPACKMAJOR VER_FLAGS = 32
	VER_SUITENAME        VER_FLAGS = 64
	VER_PRODUCT_TYPE     VER_FLAGS = 128
)

// String returns the VER_FLAGS constant's name, or its numeric form when
// the value is not a known constant.
func (e VER_FLAGS) String() string {
	var parts []string
	if e&VER_MINORVERSION != 0 {
		parts = append(parts, "VER_MINORVERSION")
	}
	if e&VER_MAJORVERSION != 0 {
		parts = append(parts, "VER_MAJORVERSION")
	}
	if e&VER_BUILDNUMBER != 0 {
		parts = append(parts, "VER_BUILDNUMBER")
	}
	if e&VER_PLATFORMID != 0 {
		parts = append(parts, "VER_PLATFORMID")
	}
	if e&VER_SERVICEPACKMINOR != 0 {
		parts = append(parts, "VER_SERVICEPACKMINOR")
	}
	if e&VER_SERVICEPACKMAJOR != 0 {
		parts = append(parts, "VER_SERVICEPACKMAJOR")
	}
	if e&VER_SUITENAME != 0 {
		parts = append(parts, "VER_SUITENAME")
	}
	if e&VER_PRODUCT_TYPE != 0 {
		parts = append(parts, "VER_PRODUCT_TYPE")
	}
	if len(parts) == 0 {
		return "0"
	}
	return strings.Join(parts, "|")
}
